  "inlineSchema": "// ==========================================================\n// SCHEMA CENTRAL - Plataforma de gestión de restaurantes\n// Locales, usuarios/roles/permisos, inventario, pedidos/clientes,\n// RRHH, recetas de cocina y ventas para BI.\n// ==========================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// -----------------------------\n// LOCALES\n// -----------------------------\nmodel Location {\n  id        String   @id @default(uuid())\n  name      String\n  city      String\n  country   String\n  currency  String // moneda \"nativa\" del local, ej. USD o COP\n  createdAt DateTime @default(now())\n\n  users        User[]\n  suppliers    Supplier[]\n  inventory    InventoryItem[]\n  purchases    Purchase[]\n  orders       Order[]\n  recipes      Recipe[]\n  shifts       Shift[]\n  timeOffs     TimeOff[]\n  serviceStats ServiceStat[]\n  menuItems    MenuItem[]\n}\n\n// -----------------------------\n// USUARIOS Y ROLES / PERMISOS (RBAC)\n// -----------------------------\nenum ModuleName {\n  INVENTORY // inventario, compras, proveedores\n  CRM // pedidos y clientes\n  HR // RRHH\n  KITCHEN // recetas y normas\n  BI // dashboard de negocio\n  ADMIN // gestión de usuarios/roles\n  ORDERS // pedidos online + POS en tiempo real\n}\n\nenum PermissionAction {\n  READ\n  WRITE\n}\n\nmodel Role {\n  id          String  @id @default(uuid())\n  key         String  @unique\n  name        String\n  description String?\n\n  users       User[]\n  permissions RolePermission[]\n}\n\nmodel RolePermission {\n  id     String           @id @default(uuid())\n  roleId String\n  module ModuleName\n  action PermissionAction\n  role   Role             @relation(fields: [roleId], references: [id], onDelete: Cascade)\n\n  @@unique([roleId, module, action])\n}\n\nmodel User {\n  id           String    @id @default(uuid())\n  email        String    @unique\n  passwordHash String\n  name         String\n  active       Boolean   @default(true)\n  roleId       String\n  role         Role      @relation(fields: [roleId], references: [id])\n  locationId   String?\n  location     Location? @relation(fields: [locationId], references: [id])\n  createdAt    DateTime  @default(now())\n}\n\n// -----------------------------\n// INVENTARIO / COMPRAS / PROVEEDORES\n// -----------------------------\nmodel Supplier {\n  id         String   @id @default(uuid())\n  name       String\n  contact    String?\n  locationId String\n  location   Location @relation(fields: [locationId], references: [id])\n\n  items     InventoryItem[]\n  purchases Purchase[]\n}\n\nmodel InventoryItem {\n  id           String   @id @default(uuid())\n  name         String\n  unit         String\n  currentStock Float    @default(0)\n  minStock     Float    @default(0)\n  price        Float\n  currency     String   @default(\"USD\")\n  supplierId   String\n  supplier     Supplier @relation(fields: [supplierId], references: [id])\n  locationId   String\n  location     Location @relation(fields: [locationId], references: [id])\n  updatedAt    DateTime @updatedAt\n\n  @@index([locationId])\n}\n\nmodel Purchase {\n  id         String   @id @default(uuid())\n  supplierId String\n  supplier   Supplier @relation(fields: [supplierId], references: [id])\n  locationId String\n  location   Location @relation(fields: [locationId], references: [id])\n  itemName   String\n  quantity   Float\n  unitPrice  Float\n  currency   String\n  createdAt  DateTime @default(now())\n}\n\n// -----------------------------\n// PEDIDOS / CLIENTES (CRM + IA de sugerencias)\n// -----------------------------\nmodel Customer {\n  id          String   @id @default(uuid())\n  name        String\n  email       String?\n  phone       String?\n  preferences String?\n  createdAt   DateTime @default(now())\n\n  orders Order[]\n}\n\nenum OrderStatus {\n  RECEIVED\n  PREPARING\n  READY\n  COMPLETED\n  CANCELLED\n}\n\nenum OrderSource {\n  ONLINE\n  POS\n  COUNTER\n}\n\nenum PaymentStatus {\n  PENDING\n  PAID\n  FAILED\n  REFUNDED\n  NOT_APPLICABLE\n}\n\nmodel Order {\n  id         String      @id @default(uuid())\n  customerId String\n  customer   Customer    @relation(fields: [customerId], references: [id])\n  locationId String\n  location   Location    @relation(fields: [locationId], references: [id])\n  items      OrderItem[]\n  totalUsd   Float\n  totalCop   Float?\n  createdAt  DateTime    @default(now())\n\n  status          OrderStatus @default(RECEIVED)\n  source          OrderSource @default(ONLINE)\n  fulfillment     String      @default(\"pickup\")\n  deliveryAddress String?\n\n  paymentStatus         PaymentStatus @default(PENDING)\n  stripeSessionId       String?       @unique\n  stripePaymentIntentId String?\n  updatedAt             DateTime      @updatedAt\n\n  @@index([locationId, status])\n}\n\nmodel OrderItem {\n  id         String  @id @default(uuid())\n  orderId    String\n  order      Order   @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  dishName   String\n  quantity   Int\n  unitPrice  Float\n  menuItemId String?\n}\n\nmodel MenuItem {\n  id          String   @id @default(uuid())\n  name        String\n  nameEn      String?\n  description String?\n  category    String\n  price       Float\n  currency    String   @default(\"USD\")\n  imageUrl    String?\n  available   Boolean  @default(true)\n  locationId  String\n  location    Location @relation(fields: [locationId], references: [id])\n  updatedAt   DateTime @updatedAt\n\n  @@index([locationId, available])\n}\n\n// -----------------------------\n// RRHH\n// -----------------------------\nmodel Employee {\n  id       String  @id @default(uuid())\n  name     String\n  position String\n  email    String  @unique\n  active   Boolean @default(true)\n\n  timeOffs TimeOff[]\n  shifts   Shift[]\n}\n\nmodel TimeOff {\n  id         String   @id @default(uuid())\n  employeeId String\n  employee   Employee @relation(fields: [employeeId], references: [id])\n  locationId String\n  location   Location @relation(fields: [locationId], references: [id])\n  type       String\n  startDate  DateTime\n  endDate    DateTime\n  approved   Boolean  @default(false)\n}\n\nmodel Shift {\n  id         String   @id @default(uuid())\n  employeeId String\n  employee   Employee @relation(fields: [employeeId], references: [id])\n  locationId String\n  location   Location @relation(fields: [locationId], references: [id])\n  startTime  DateTime\n  endTime    DateTime\n}\n\nmodel ServiceStat {\n  id               String   @id @default(uuid())\n  locationId       String\n  location         Location @relation(fields: [locationId], references: [id])\n  date             DateTime\n  noShows          Int      @default(0)\n  reservations     Int      @default(0)\n  tableTurnoverMin Float?\n  avgMealTimeMin   Float?\n}\n\n// -----------------------------\n// COCINA\n// -----------------------------\nmodel Recipe {\n  id             String    @id @default(uuid())\n  nameEs         String\n  nameEn         String\n  instructionsEs String\n  instructionsEn String\n  rulesEs        String?\n  rulesEn        String?\n  locationId     String?\n  location       Location? @relation(fields: [locationId], references: [id])\n  updatedAt      DateTime  @updatedAt\n}\n",
